VALUES
  ('social-worker-moex-06670', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列有關現金給付（in-cash）、實物給付（in-kind）與各種福利券（voucher）性質的敘述，何者比較正確？', '["提供現金給付，可以讓服務使用者依自己意願自由地運用金錢，但它卻無法保有自尊、減少烙印感受", "提供實物給付，可以讓服務使用者得到實質的、社會所希望的幫助，同時它也可以確保選擇的自由", "提供福利券式的給付，可以讓服務使用者在保留部分選擇自由的同時，又允許一定程度的社會控制", "比較三者的行政成本，由高到低，依序分別是：現金給付＞實物給付＞福利券式的給付"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06671', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列有關社會救助、社會保險、和社會津貼敘述，就一般情形來說，何者比較正確？', '["就給付資格的寬鬆程度比較：社會救助最寬，社會津貼最窄", "就給付水準的高低程度比較：社會救助最高，社會津貼最低", "就給付行政的層級比較：社會救助由中央政府主導層級最高，社會保險是地方政府辦理層級最低", "就財源籌措方式的比較：社會救助來自一般稅收，社會保險主要來自保險費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06672', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請挑出老人福利法中老人經濟安全保障內容正確組合？①醫療保險 ②年金保險 ③特別照顧津貼 ④生 活津貼', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06673', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '當社會工作者執行業務時知悉某少年施用毒品，應立即向直轄市、縣（市）主管機關通報，至遲不得超 過幾小時？', '["24小時", "36小時", "48小時", "72小時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06674', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依兒童及少年福利與權益保障法規定，若父母不接受或拒不完成親職教育輔導時，其正確罰鍰為何？', '["處新臺幣1000元以上5000元以下罰鍰；經再通知仍不接受者，得按次處罰至其參加為止", "處新臺幣1000元以上10000元以下罰鍰；經再通知仍不接受者，得按次處罰至其參加為止", "處新臺幣1500元以上15000元以下罰鍰；經再通知仍不接受者，得按次處罰至其參加為止", "處新臺幣3000元以上15000元以下罰鍰；經再通知仍不接受者，得按次處罰至其參加為止"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06675', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據身心障礙者權益保障法規定，下列身心障礙者經濟安全保障的敘述，何者比較正確？', '["身心障礙者經濟安全保障，採生活補助、日間照顧及住宿式照顧補助、照顧者津貼、及年金保險等方 式逐步規劃實施", "主管機關對轄區內之身心障礙者，應依需求評估結果，提供各項補助，但有設籍一年的時間限制", "身心障礙者各項費用補助的內容，以生活補助、日間照顧及住宿式照顧費用、以及醫療費用三項為限", "不符合請領資格而領取補助者，由主管機關以書面命本人自事實發生之日起三十日內繳還"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06676', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依家庭暴力防治法規定，除非屬全民健保給付範圍之醫療及身心治療、諮商與輔導費、和其他必要費用', '["子女教育、生活及兒童托育費", "訴訟及律 師費", "安置、房屋租金費", "一般生活補償費"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06677', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依社會救助法規定，不列入家庭應計算人口範圍的人員敘述，下列何者正確？', '["已設有戶籍之非本國籍配偶或大陸地區配偶", "有共同生活且扶養事實之特定境遇單親家庭直系血親尊親屬", "應徵集召集入營服兵役或替代役現役", "失蹤，經向警察機關報案協尋未獲，達三個月以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06678', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依社會工作師法規定，社會工作師犯何種罪經有罪判決確定後，撤銷或廢止其社會工作師證書？', '["貪污罪、偽造文書印文罪、性騷擾罪、妨害性自主罪", "貪污罪、瀆職罪、性騷擾罪、妨害性自主罪", "貪污罪、家庭暴力罪、性騷擾罪、妨害性自主罪", "貪污罪、妨害秩序罪、性騷擾罪、妨害性自主罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06679', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依兒童及少年性交易防制條例規定，國民中小學一旦發現學生未經請假、不明原因未到校上課達幾天以 上者，應立即通知主管機關及教育主管機關？', '["3天", "5天", "7天", "12天"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
